+	return &protos.HistoryEvent{
+		EventId: eventID,
+		EventType: &protos.HistoryEvent_TaskCompleted{
+			TaskCompleted: &protos.TaskCompletedEvent{TaskScheduledId: scheduledID},
+		},
+	}
+}
